<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { dayNames, therapistStateLabel } from '../lib/admin'
import { useAdminStore } from '../stores/admin'
import type { AdminStaffDetail } from '../lib/api'
const store=useAdminStore();const editorOpen=ref(false);const editing=ref<AdminStaffDetail|null>(null)
const form=reactive({name:'',email:'',phone:'',staff_type:'therapist',position:'',specialization:'',bio:'',hire_date:'',is_active:true,is_bookable:true,service_ids:[] as number[]})
const shift=reactive({day_of_week:1,start_time:'13:00',end_time:'18:00',ends_next_day:false,is_available:true})
const exceptionForm=reactive({exception_date:new Date().toISOString().slice(0,10),exception_type:'unavailable',start_time:'',end_time:'',ends_next_day:false,reason:''})
onMounted(()=>Promise.all([store.loadStaff(),store.loadStaffOptions()]))
async function openDetail(id:number):Promise<void>{await store.openStaff(id)}
function createStaff():void{editing.value=null;Object.assign(form,{name:'',email:'',phone:'',staff_type:'therapist',position:'',specialization:'',bio:'',hire_date:'',is_active:true,is_bookable:true,service_ids:[]});store.clear();editorOpen.value=true}
function editStaff(item:AdminStaffDetail):void{editing.value=item;Object.assign(form,{name:item.name??'',email:item.email??'',phone:item.phone??'',staff_type:item.staff_type,position:item.position??'',specialization:item.specialization??'',bio:item.bio??'',hire_date:item.hire_date??'',is_active:item.is_active,is_bookable:item.is_bookable,service_ids:item.services.map(service=>service.id)});store.clear();editorOpen.value=true}
async function save():Promise<void>{if(await store.saveStaff({...form},editing.value?.id))editorOpen.value=false}
async function addShift():Promise<void>{if(store.selectedStaff)await store.addWeeklySchedule(store.selectedStaff.id,{...shift})}
async function addException():Promise<void>{if(store.selectedStaff)await store.addException(store.selectedStaff.id,{...exceptionForm,start_time:exceptionForm.start_time||null,end_time:exceptionForm.end_time||null})}
</script>
<template><section class="page"><header><p class="eyebrow">TEAM & AVAILABILITY</p><h1>Therapists</h1><p>Manage eligibility, specialties, assigned services, and recurring shifts.</p></header><div class="metrics"><article><strong>{{store.staffSummary.active}}</strong><span>Active</span></article><article><strong>{{store.staffSummary.bookable}}</strong><span>Bookable</span></article><article><strong>{{store.staffSummary.inactive}}</strong><span>Inactive</span></article></div><p v-if="store.notice" class="notice">{{store.notice}}</p><p v-if="store.error" class="alert">{{store.error}}</p><form class="filters" @submit.prevent="store.loadStaff(1)"><input v-model="store.staffSearch" aria-label="Search therapists" placeholder="Search therapists"><select v-model="store.staffStatus" aria-label="Account status"><option value="">All accounts</option><option value="active">Active</option><option value="inactive">Inactive</option></select><select v-model="store.staffBookable" aria-label="Booking status"><option value="">All booking states</option><option value="yes">Bookable</option><option value="no">Not bookable</option></select><button>Apply</button></form><button v-if="store.staffOptions?.can_create" class="primary" @click="createStaff">Create therapist access</button><div class="list"><button v-for="item in store.staff" :key="item.id" class="card" @click="openDetail(item.id)"><div class="top"><span>{{therapistStateLabel(item.is_active,item.is_bookable)}}</span><small>{{item.appointments_count}} visits</small></div><h2>{{item.name}}</h2><p>{{item.position||item.staff_type}} · {{item.specialization||'General wellness'}}</p><small>{{item.services.map(service=>service.name).join(', ')||'No assigned services'}}</small></button><p v-if="!store.loading&&!store.staff.length" class="empty">No therapists found.</p></div><div class="pager" v-if="store.staffMeta.last_page>1"><button :disabled="store.staffMeta.current_page===1" @click="store.loadStaff(store.staffMeta.current_page-1)">Previous</button><span>Page {{store.staffMeta.current_page}} of {{store.staffMeta.last_page}}</span><button :disabled="store.staffMeta.current_page===store.staffMeta.last_page" @click="store.loadStaff(store.staffMeta.current_page+1)">Next</button></div>
<section v-if="store.selectedStaff" class="sheet"><header><div><p class="eyebrow">THERAPIST RECORD</p><h2>{{store.selectedStaff.name}}</h2></div><button aria-label="Close therapist details" @click="store.selectedStaff=null">×</button></header><div class="detail"><section><div class="top"><span>{{therapistStateLabel(store.selectedStaff.is_active,store.selectedStaff.is_bookable)}}</span><button class="text-button" @click="editStaff(store.selectedStaff)">Edit profile</button></div><p>{{store.selectedStaff.email}} · {{store.selectedStaff.phone||'No phone'}}</p><p>{{store.selectedStaff.position||'Therapist'}} · {{store.selectedStaff.specialization||'General wellness'}}</p><p>{{store.selectedStaff.bio||'No biography recorded.'}}</p><small>{{store.selectedStaff.services.map(service=>service.name).join(', ')||'No assigned services'}}</small></section><section><h3>Recurring shifts</h3><article v-for="item in store.selectedStaff.weekly_schedules" :key="item.id" class="shift"><span><strong>{{dayNames[item.day_of_week]}}</strong><small>{{item.start_time}}–{{item.ends_next_day?'12:00 midnight':item.end_time}}</small></span><button :disabled="store.working" @click="store.removeWeeklySchedule(store.selectedStaff!.id,item.id)">Remove</button></article><p v-if="!store.selectedStaff.weekly_schedules.length">No recurring shifts.</p><form class="shift-form" @submit.prevent="addShift"><select v-model.number="shift.day_of_week" aria-label="Shift day"><option v-for="(day,index) in dayNames" :key="day" :value="index">{{day}}</option></select><input v-model="shift.start_time" type="time" min="13:00" required aria-label="Shift start"><input v-model="shift.end_time" type="time" required aria-label="Shift end"><label><input v-model="shift.ends_next_day" type="checkbox"> Ends at midnight</label><button :disabled="store.working">Add shift</button></form></section><section><h3>Upcoming exceptions</h3><article v-for="item in store.selectedStaff.schedule_exceptions" :key="item.id" class="shift"><span><strong>{{item.exception_date}} · {{item.exception_type}}</strong><small>{{item.start_time&&item.end_time?`${item.start_time}–${item.end_time}`:'Full business day'}} · {{item.reason||'No reason'}}</small></span><button @click="store.removeException(store.selectedStaff!.id,item.id)">Remove</button></article><p v-if="!store.selectedStaff.schedule_exceptions.length">No upcoming exceptions.</p><form class="shift-form" @submit.prevent="addException"><input v-model="exceptionForm.exception_date" type="date" required aria-label="Exception date"><select v-model="exceptionForm.exception_type" aria-label="Exception type"><option value="unavailable">Unavailable</option><option value="available">Available override</option></select><input v-model="exceptionForm.start_time" type="time" min="13:00" aria-label="Exception start"><input v-model="exceptionForm.end_time" type="time" aria-label="Exception end"><input v-model="exceptionForm.reason" placeholder="Reason" aria-label="Exception reason"><button :disabled="store.working">Add exception</button></form></section></div></section>
<section v-if="editorOpen" class="sheet editor-sheet"><header><div><p class="eyebrow">{{editing?'UPDATE':'CREATE'}} ACCESS</p><h2>{{editing?.name??'New therapist'}}</h2></div><button aria-label="Close therapist form" @click="editorOpen=false">×</button></header><form class="editor" @submit.prevent="save"><label>Name<input v-model="form.name" required></label><label>Email<input v-model="form.email" type="email" :readonly="!!editing" required></label><label>Phone<input v-model="form.phone"></label><label>Position<input v-model="form.position"></label><label>Specialization<input v-model="form.specialization"></label><label>Hire date<input v-model="form.hire_date" type="date"></label><label>Biography<textarea v-model="form.bio" rows="4"/></label><fieldset><legend>Assigned services</legend><label v-for="service in store.staffOptions?.services" :key="service.id" class="check"><input v-model="form.service_ids" type="checkbox" :value="service.id">{{service.name}}</label></fieldset><label class="check"><input v-model="form.is_active" type="checkbox"> Active account</label><label class="check"><input v-model="form.is_bookable" type="checkbox"> Available for booking</label><p v-if="store.error" class="alert">{{store.error}}</p><button class="primary" :disabled="store.working">{{store.working?'Saving…':'Save therapist'}}</button></form></section></section></template>
<style scoped>
.page{width:min(100%,54rem);margin:auto;padding:max(5.2rem,calc(env(safe-area-inset-top) + 4.4rem)) 1rem calc(6rem + env(safe-area-inset-bottom))}.page h1,.page h2,.sheet h2,.sheet h3{font-family:Georgia,serif;color:#334736}.page h1{margin:.25rem 0}.page header>p:last-child{color:#67675f}.metrics{display:grid;grid-template-columns:repeat(3,1fr);gap:.5rem;margin:1rem 0}.metrics article{display:grid;padding:.75rem;border:1px solid #dcd2c2;border-radius:.8rem;background:#fffcf7}.metrics strong{font:700 1.25rem Georgia,serif}.metrics span{font-size:.68rem;color:#67675f}.filters{display:grid;grid-template-columns:1fr 1fr;gap:.5rem;margin:1rem 0}.filters input,.filters select,.filters button,.editor input,.editor textarea,.shift-form input,.shift-form select{min-height:48px;border:1px solid #bfb3a2;border-radius:.7rem;background:#fff;padding:.65rem;font:inherit}.filters button{background:#4f6a4e;color:white;font-weight:800}.primary{min-height:48px;width:100%;border:0;border-radius:.75rem;background:#4f6a4e;color:white;font-weight:800}.list{display:grid;gap:.65rem;margin-top:1rem}.card{display:grid;gap:.35rem;width:100%;padding:1rem;border:1px solid #dcd2c2;border-radius:1rem;background:#fffcf7;text-align:left;color:#232620}.card h2{margin:.2rem 0}.card p,.card small{color:#67675f}.top{display:flex;justify-content:space-between;align-items:center;gap:.5rem}.top>span{padding:.2rem .55rem;border-radius:999px;background:#e9f2e8;font-size:.72rem}.pager{display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:.5rem;margin-top:1rem}.pager button{min-height:44px;border:1px solid #dcd2c2;border-radius:.7rem;background:#fff}.pager span{text-align:center;font-size:.75rem}.sheet{position:fixed;z-index:30;inset:0;overflow:auto;background:#f5f0e7;padding:max(1rem,env(safe-area-inset-top)) 1rem max(1rem,env(safe-area-inset-bottom))}.editor-sheet{z-index:35}.sheet>header,.detail,.editor{max-width:42rem;margin:auto}.sheet>header{display:flex;justify-content:space-between}.sheet>header button{width:48px;height:48px;border:1px solid #dcd2c2;border-radius:999px;background:#fff;font-size:1.5rem}.detail{display:grid;gap:1rem}.detail>section{padding:1rem;border:1px solid #dcd2c2;border-radius:1rem;background:#fffcf7}.text-button{min-height:44px;border:1px solid #bfb3a2;border-radius:.65rem;background:#fff;font-weight:800}.shift{display:flex;justify-content:space-between;align-items:center;gap:.5rem;padding:.65rem 0;border-top:1px solid #eee5d8}.shift span{display:grid}.shift small{color:#67675f}.shift button{min-height:40px;border:1px solid #bfb3a2;border-radius:.6rem;background:#fff}.shift-form,.editor{display:grid;gap:.75rem}.shift-form label,.editor label{display:grid;gap:.35rem;font-weight:700}.shift-form button{min-height:48px;border:0;border-radius:.7rem;background:#4f6a4e;color:white;font-weight:800}.editor fieldset{display:grid;gap:.45rem;border:1px solid #dcd2c2;border-radius:.8rem;padding:.8rem}.editor .check,.shift-form label{grid-template-columns:auto 1fr;align-items:center}.editor .check input,.shift-form input[type=checkbox]{width:24px;min-height:24px}.empty{text-align:center;padding:1.5rem}
</style>
